// marshalTypesTunneledMcpServerToTunneledMcpServerResponseBody builds a value
// of type *TunneledMcpServerResponseBody from a value of type
// *types.TunneledMcpServer.
func marshalTypesTunneledMcpServerToTunneledMcpServerResponseBody(v *types.TunneledMcpServer) *TunneledMcpServerResponseBody {
	res := &TunneledMcpServerResponseBody{
		ID:                         v.ID,
		ProjectID:                  v.ProjectID,
		Name:                       v.Name,
		KeyPrefix:                  v.KeyPrefix,
		Status:                     string(v.Status),
		ConnectionStatus:           string(v.ConnectionStatus),
		AgentVersion:               v.AgentVersion,
		LastSeenAt:                 v.LastSeenAt,
		ActiveConnectionCount:      v.ActiveConnectionCount,
		ActiveConsumerSessionCount: v.ActiveConsumerSessionCount,
		CreatedAt:                  v.CreatedAt,
		UpdatedAt:                  v.UpdatedAt,
	}

	return res
}

// marshalTypesTunneledMcpConnectionToTunneledMcpConnectionResponseBody builds
// a value of type *TunneledMcpConnectionResponseBody from a value of type
// *types.TunneledMcpConnection.
func marshalTypesTunneledMcpConnectionToTunneledMcpConnectionResponseBody(v *types.TunneledMcpConnection) *TunneledMcpConnectionResponseBody {
	res := &TunneledMcpConnectionResponseBody{
		GatewaySessionID:       v.GatewaySessionID,
		ServiceID:              v.ServiceID,
		ServiceSlug:            v.ServiceSlug,
		ServiceVersion:         v.ServiceVersion,
		AgentVersion:           v.AgentVersion,
		ConnectedAt:            v.ConnectedAt,
		LastHeartbeatAt:        v.LastHeartbeatAt,
		RemoteAddr:             v.RemoteAddr,
		ActiveSubstreams:       v.ActiveSubstreams,
		ActiveConsumerSessions: v.ActiveConsumerSessions,
	}
	if v.Metadata != nil {
		res.Metadata = make(map[string]string, len(v.Metadata))
		for key, val := range v.Metadata {
			tk := key
			tv := val
			res.Metadata[tk] = tv
		}
	}

	return res
}
